<template>
  <LTPages
      :title="'版本'"
      isNormal
  >
    <template v-slot:content>
      <!--版本-->
      <div class="versions-body">




        <!--0.0.1版本更新内容 START-->
        <div class="body-title">
          <i class="icon zhb-iconfont zhb-iconxiangmuguanli"></i>
          ^0.0.1
        </div>
        <!--说明-->
        <div class="zhb-allnum-tip">
          <h3>自定义组件 </h3>
          <div class="Versions-Title" @click="$router.push('/HeadTooltip')">1、<span>表格表头可配置提示词。</span></div>
          <div class="Versions-Title" @click="$router.push('/MultilevelHead')">2、<span>表格表头可配置二级表头。</span></div>
        </div>
        <div class="zhb-title">版本下载
         <p style="font-size: 14px;color: red;">下载完成后， 将压缩包解压后移动根目录下packages中。</p>
        </div>
        <el-button @click="downloadZip('1.2.56')">^1.2.56</el-button>

        <!--^0.0.1 END-->

      </div>


    </template>
  </LTPages>
</template>

<script>

import codeCopy from "@/components/code"

export default {
  components: {
    codeCopy
  },
  data() {
    return {}
  },
  methods: {
    downloadZip(versions) {
      const link = document.createElement('a');
      link.href = `/download/LTUIPro^${versions}.zip`; // 这里的路径是相对于 public 目录的
      //link.href = process.env.VUE_APP_PUBLIC_PATH + `/download/LTUI^${versions}.zip`,
      link.download = `LTUIPro^${versions}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    }
  }
}
</script>

<style scoped lang="scss">
.Versions-Title{
  width: 100%;
  margin-bottom: 10px;
  span{
    color: #409EFF;
    border-bottom: 1px solid #409EFF;
    cursor: pointer;
  }
}
.versions-body{
  height: calc(100% - 170px);
  margin: 0 40px;overflow: auto;
  &::-webkit-scrollbar{
    width: 4px;
  }
}
</style>